#!/bin/bash
# Executive Assistant - Next.js Setup Script
# Run: bash setup.sh
# This will decode and run setup.js which generates all project files

echo "Decoding setup.js from embedded data..."

# Decode the base64 gzip data
cat << 'GZDATA' | base64 -d | gunzip > setup.js

GZDATA

if [ $? -eq 0 ]; then
  echo "Successfully decoded setup.js"
  echo "Running setup.js to generate project files..."
  node setup.js
  echo "Done! Run npm install && npm run dev to start."
else
  echo "Error decoding setup.js"
  exit 1
fi
